package com.example.plantastic.notifications;

import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;

import androidx.core.app.NotificationCompat;

import com.example.plantastic.MainActivity;
import com.example.plantastic.R;

public class CareNotificationManager {
    private static final String CHANNEL_ID = "care_notifications";
    private static final int NOTIFICATION_ID = 1;

    public static void createNotificationChannel(Context context) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel(
                    CHANNEL_ID,
                    "Care Notifications",
                    NotificationManager.IMPORTANCE_HIGH
            );
            channel.setDescription("Notifications for plant care reminders");

            NotificationManager notificationManager = 
                    context.getSystemService(NotificationManager.class);
            if (notificationManager != null) {
                notificationManager.createNotificationChannel(channel);
            }
        }
    }

    public static void showCareNotification(Context context, int taimId, String plantName, String careType) {
        createNotificationChannel(context);

        Intent openIntent = new Intent(context, MainActivity.class);
        openIntent.putExtra("plantId", taimId);
        openIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);

        PendingIntent openPendingIntent = PendingIntent.getActivity(
                context,
                taimId,
                openIntent,
                PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE
        );

        Intent snoozeIntent = new Intent(context, SnoozeNotificationReceiver.class);
        snoozeIntent.putExtra("taim_id", taimId);
        snoozeIntent.putExtra("hooldus_type_id", 1); // Default to Kastmine(1) for now

        PendingIntent snoozePendingIntent = PendingIntent.getBroadcast(
                context,
                taimId + 1000,
                snoozeIntent,
                PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE
        );

        NotificationCompat.Builder builder = new NotificationCompat.Builder(context, CHANNEL_ID)
                .setSmallIcon(R.drawable.ic_launcher_foreground)
                .setContentTitle("Taim vajab hooldust")
                .setContentText(plantName + " - " + careType)
                .setStyle(new NotificationCompat.BigTextStyle()
                        .bigText(plantName + " (" + careType + ") vajab hooldust"))
                .setPriority(NotificationCompat.PRIORITY_HIGH)
                .setAutoCancel(true)
                .setContentIntent(openPendingIntent)
                .addAction(R.drawable.ic_launcher_foreground, "Snooze 1h", snoozePendingIntent);

        NotificationManager notificationManager = 
                context.getSystemService(NotificationManager.class);
        if (notificationManager != null) {
            notificationManager.notify(NOTIFICATION_ID + taimId, builder.build());
        }
    }
}

package com.example.plantastic.notifications;

import android.content.Context;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.work.Worker;
import androidx.work.WorkerParameters;

import com.example.plantastic.data.PlantasticDatabase;
import com.example.plantastic.data.entities.Taim;
import com.example.plantastic.data.entities.Teade;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class CareNotificationWorker extends Worker {
    private static final String TAG = "CareNotificationWorker";

    public CareNotificationWorker(@NonNull Context context, @NonNull WorkerParameters params) {
        super(context, params);
    }

    @NonNull
    @Override
    public Result doWork() {
        try {
            PlantasticDatabase db = PlantasticDatabase.getInstance(getApplicationContext());
            long now = System.currentTimeMillis();

            // Get all notifications that are due
            List<Teade> dueNotifications = db.teadeDao().getUpcoming(now - 1000); // slight buffer

            Set<Integer> sentPlantIds = new HashSet<>();

            if (dueNotifications != null) {
                for (Teade teade : dueNotifications) {
                    // Only send one notification per plant to avoid spam
                    if (!sentPlantIds.contains(teade.taim_id) && teade.aeg <= now) {
                        Taim taim = db.taimDao().getById(teade.taim_id);
                        String careType = getCareTypeName(db, teade.hooldusTüüp_id);

                        if (taim != null) {
                            CareNotificationManager.showCareNotification(
                                    getApplicationContext(),
                                    taim.id,
                                    taim.nimi,
                                    careType
                            );
                            sentPlantIds.add(teade.taim_id);
                            Log.d(TAG, "Notification sent for plant: " + taim.nimi);
                        }
                    }
                }
            }

            return Result.success();
        } catch (Exception ex) {
            Log.e(TAG, "Error checking notifications", ex);
            return Result.retry();
        }
    }

    private String getCareTypeName(PlantasticDatabase db, Integer typeId) {
        if (typeId == null) return "Care";
        try {
            com.example.plantastic.data.entities.HooldusTüüp type = db.hooldusTüüpDao().getById(typeId);
            return type != null ? type.nimetus : "Care";
        } catch (Exception e) {
            return "Care";
        }
    }
}

package com.example.plantastic.notifications;

import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.util.Log;

import com.example.plantastic.data.PlantasticDatabase;
import com.example.plantastic.data.entities.Teade;

public class SnoozeNotificationReceiver extends BroadcastReceiver {
    private static final String TAG = "SnoozeNotificationReceiver";
    private static final long SNOOZE_DURATION_MS = 60 * 60 * 1000; // 1 hour

    @Override
    public void onReceive(Context context, Intent intent) {
        int taimId = intent.getIntExtra("taim_id", -1);
        Integer hooldusTypeId = intent.getIntExtra("hooldus_type_id", 1);

        if (taimId != -1) {
            new Thread(() -> {
                try {
                    PlantasticDatabase db = PlantasticDatabase.getInstance(context);

                    // Get the notification for this plant and care type
                    Teade teade = db.teadeDao().getByTaimAndType(taimId, hooldusTypeId);

                    if (teade != null) {
                        // Reschedule to 1 hour from now
                        teade.aeg = System.currentTimeMillis() + SNOOZE_DURATION_MS;
                        db.teadeDao().update(teade);
                        Log.d(TAG, "Notification snoozed for plant " + taimId);
                    }
                } catch (Exception ex) {
                    Log.e(TAG, "Error snoozing notification", ex);
                }
            }).start();
        }
    }
}
